#include<iostream>
#include<cstdio>
using namespace std;
int dp2[105],dp[105],a[105],maxx=-1;
int main()
{
	int n;
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		dp[i]=1;
		dp2[i]=1;
	}
	for(int i=n-1;i>=1;i--)
	{
		for(int j=i+1;j<=n;j++)
		{
			if(a[i]>a[j]&&dp[i]<=dp[j]+1) dp[i]=dp[j]+1;
		}
    }
	for(int i=2;i<=n;i++)
	{
		for(int j=1;j<i;j++)
		{
			if(a[i]>a[j]&&dp2[i]<=dp2[j]+1) dp2[i]=dp2[j]+1;
		}
	}
	for(int i=1;i<=n;i++)
	{
		int t=dp[i]+dp2[i]-1;
		if(t>maxx) maxx=t;
	}
	cout<<n-maxx;
}
